#!/bin/bash

KEY_ARN="arn:aws:payment-cryptography:us-east-1:839834288637:key/a6o2bpzd6zfolfxx"
CIPHERED_DATA_HEX=""

echo "Ciphered Data (Base64): $CIPHERED_DATA"
echo "Ciphered Data (Hex): $CIPHERED_DATA_HEX"

aws payment-cryptography-data decrypt-data \
    --key-identifier $KEY_ARN \
    --cipher-text $CIPHERED_DATA_HEX \
    --decryption-attributes '{
        "Symmetric": {
            "Mode": "CBC",
            "InitializationVector": "99E72E6A7C537942465A13D4554B017B"
        }
    }'
        